// SELECT THE SPECIFIC FILE TO TEST
// This workflow will report EACH failed test case individually via email.
return [{
  json: {
    product: 'ERP',
    folder: 'ERP',
    filename: 'ProjectDashboard.spec.js',
    testPath: 'tests/ERP/ProjectDashboard.spec.js'
  }
}];

const { execSync } = require('child_process');
const item = $input.item.json;

const cwd = 'C:/Users/veeramani/desktop/playwright-mcp';
const testPath = item.testPath;
const cmd = `npx playwright test "${testPath}" --reporter=json`;

const startTime = new Date();
let stdout = '';
let stderr = '';
let exitCode = 0;

try {
  stdout = execSync(cmd, { cwd, stdio: 'pipe', timeout: 300000 }).toString();
} catch (e) {
  exitCode = e.status || 1;
  stdout = (e.stdout || '').toString();
  stderr = (e.stderr || e.message || '').toString();
}

const endTime = new Date();
const duration = ((endTime - startTime) / 1000).toFixed(2);

return {
  json: {
    ...item,
    exitCode: exitCode,
    rawStdout: stdout,
    stderr: (stderr || '').substring(0, 1000),
    status: exitCode === 0 ? 'passed' : 'failed',
    duration: `${duration}s`,
    timestamp: new Date().toISOString()
  }
};

const item = $input.item.json;
const stdout = item.rawStdout;
const cwd = 'C:/Users/veeramani/desktop/playwright-mcp';
let failures = [];

try {
  const jsonMatch = stdout.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const jsonData = JSON.parse(jsonMatch[0]);

    function processSuite(suite, parents = []) {
      const suiteTitle = parents.concat(suite.title || []).filter(t => t);

      if (suite.specs) {
        suite.specs.forEach(spec => {
          const specTitle = suiteTitle.concat(spec.title).join(' > ');
          spec.tests.forEach(test => {
            const results = test.results || [];
            // Check if any result in the test was a failure
            const failedResult = results.find(r => r.status === 'failed');
            if (failedResult) {
               const screenshot = (failedResult.attachments || []).find(a => a.name === 'screenshot');
               failures.push({
                   filename: item.filename,
                   testTitle: specTitle,
                   status: 'failed',
                   error: failedResult.errors && failedResult.errors.length > 0 
                       ? failedResult.errors.map(e => e.message || e.stack).join('\n\n') 
                       : (failedResult.error ? failedResult.error.message : 'Unknown error'),
                   screenshotPath: screenshot ? (screenshot.path.includes(':') || screenshot.path.startsWith('/') ? screenshot.path : `${cwd}/${screenshot.path}`).replace(/\\/g, '/') : null,
                   duration: (failedResult.duration / 1000).toFixed(2) + 's'
               });
            }
          });
        });
      }

      if (suite.suites) {
        suite.suites.forEach(s => processSuite(s, suiteTitle));
      }
    }

    if (jsonData.suites) {
      jsonData.suites.forEach(s => processSuite(s));
    }
  }
} catch (e) {
  if (item.status === 'failed' && failures.length === 0) {
    failures.push({
        filename: item.filename,
        testTitle: 'Test Execution Error',
        status: 'failed',
        error: item.stderr || 'Failed to parse playwright output',
        screenshotPath: null,
        duration: item.duration
    });
  }
}

return failures.map(f => ({ json: f }));
